// Inline + full-script code generators for the Classical Ciphers lesson.
//
// EDUCATIONAL ONLY. Caesar and Vigenère are broken by hand in this
// lesson. The one-time pad is unbreakable but impractical (you need a
// fresh random key as long as the message, securely shared). Don't ship
// any of these to protect real data.

const HEADER = [
  "# Classical ciphers — generated by cloak.moosha.org",
  "# EDUCATIONAL ONLY. Caesar and Vigenère can be broken by hand;",
  "# the one-time pad is unbreakable but impractical. Modern crypto",
  "# (AES, ChaCha20, etc.) is what you reach for in production.",
  "",
].join("\n");

const CAESAR_FUNCS = [
  "def caesar_encrypt(text: str, k: int) -> str:",
  "    out = []",
  "    for ch in text:",
  "        if 'A' <= ch <= 'Z':",
  "            out.append(chr((ord(ch) - 65 + k) % 26 + 65))",
  "        elif 'a' <= ch <= 'z':",
  "            out.append(chr((ord(ch) - 97 + k) % 26 + 97))",
  "        else:",
  "            out.append(ch)",
  "    return ''.join(out)",
  "",
  "def caesar_decrypt(text: str, k: int) -> str:",
  "    return caesar_encrypt(text, -k)",
].join("\n");

const VIGENERE_FUNCS = [
  "def vigenere_encrypt(text: str, key: str) -> str:",
  "    key = ''.join(c.lower() for c in key if c.isalpha())",
  "    if not key:",
  "        raise ValueError('Vigenère key must contain at least one letter')",
  "    out, ki = [], 0",
  "    for ch in text:",
  "        if ch.isalpha():",
  "            shift = ord(key[ki % len(key)]) - ord('a')",
  "            base = ord('A') if ch.isupper() else ord('a')",
  "            out.append(chr((ord(ch) - base + shift) % 26 + base))",
  "            ki += 1",
  "        else:",
  "            out.append(ch)",
  "    return ''.join(out)",
  "",
  "def vigenere_decrypt(text: str, key: str) -> str:",
  "    # Decrypt by inverting each shift letter (a stays a, b ↔ z, c ↔ y, ...).",
  "    inv = ''.join(chr((26 - (ord(k) - ord('a'))) % 26 + ord('a')) for k in key.lower())",
  "    return vigenere_encrypt(text, inv)",
].join("\n");

const FREQ_FUNCS = [
  "ENGLISH_FREQ = {",
  "    'a': 0.08167, 'b': 0.01492, 'c': 0.02782, 'd': 0.04253, 'e': 0.12702,",
  "    'f': 0.02228, 'g': 0.02015, 'h': 0.06094, 'i': 0.06966, 'j': 0.00153,",
  "    'k': 0.00772, 'l': 0.04025, 'm': 0.02406, 'n': 0.06749, 'o': 0.07507,",
  "    'p': 0.01929, 'q': 0.00095, 'r': 0.05987, 's': 0.06327, 't': 0.09056,",
  "    'u': 0.02758, 'v': 0.00978, 'w': 0.02360, 'x': 0.00150, 'y': 0.01974,",
  "    'z': 0.00074,",
  "}",
  "",
  "def freq_dist(text: str) -> dict:",
  "    counts = {c: 0 for c in 'abcdefghijklmnopqrstuvwxyz'}",
  "    total = 0",
  "    for ch in text.lower():",
  "        if ch in counts:",
  "            counts[ch] += 1",
  "            total += 1",
  "    return {c: (counts[c] / total if total else 0) for c in counts}",
  "",
  "def chi_squared(dist: dict) -> float:",
  "    return sum(((dist[c] - ENGLISH_FREQ[c]) ** 2) / ENGLISH_FREQ[c] for c in ENGLISH_FREQ)",
  "",
  "def break_caesar(ciphertext: str) -> tuple[int, str]:",
  "    best = (0, float('inf'), ciphertext)",
  "    for k in range(26):",
  "        candidate = caesar_decrypt(ciphertext, k)",
  "        score = chi_squared(freq_dist(candidate))",
  "        if score < best[1]:",
  "            best = (k, score, candidate)",
  "    return best[0], best[2]",
  "",
  "def break_vigenere(ciphertext: str, key_len: int) -> tuple[str, str]:",
  "    letters = [c for c in ciphertext if c.isalpha()]",
  "    streams = [''.join(letters[i::key_len]) for i in range(key_len)]",
  "    key = ''.join(chr(break_caesar(s)[0] + ord('a')) for s in streams)",
  "    return key, vigenere_decrypt(ciphertext, key)",
].join("\n");

const OTP_FUNCS = [
  "import os",
  "",
  "def otp_encrypt(plaintext: bytes, key: bytes) -> bytes:",
  "    if len(key) != len(plaintext):",
  "        raise ValueError('OTP key must equal message length')",
  "    return bytes(p ^ k for p, k in zip(plaintext, key))",
  "",
  "def otp_decrypt(ciphertext: bytes, key: bytes) -> bytes:",
  "    return otp_encrypt(ciphertext, key)  # XOR is self-inverse",
].join("\n");

// Inline code shown on each step (the tiny snippet under the prompt).
export const info = (_s) => "";

export const caesar = (_s) => [
  "# Caesar cipher: shift every letter by k.",
  "ciphertext = caesar_encrypt('HELLO', 3)  # → 'KHOOR'",
].join("\n");

export const caesar_decrypt_step = (s) => {
  const shift = s.cc_caesar_shift;
  const ct = s.cc_caesar_ciphertext;
  const pt = s.cc_caesar_plaintext;
  if (shift === undefined || ct === undefined) {
    return "# Try all 26 shifts; one of them spells English.\nfor k in range(26):\n    print(k, caesar_decrypt(ciphertext, k))";
  }
  return [
    `# Shift = ${shift} was the key.`,
    `caesar_decrypt(${JSON.stringify(ct)}, ${shift})`,
    `# → ${JSON.stringify(pt)}`,
  ].join("\n");
};

export const vigenere = (_s) => [
  "# Vigenère: repeat a keyword across the plaintext.",
  "vigenere_encrypt('ATTACKATDAWN', 'LEMON')  # → 'LXFOPVEFRNHR'",
].join("\n");

export const frequency_analysis = (_s) => [
  "# English letter frequencies (E ~12.7%, T ~9.1%, A ~8.2%, ...).",
  "freq_dist('the quick brown fox')",
].join("\n");

export const vigenere_break_step = (s) => {
  const recovered = s.cc_vigenere_recovered_key;
  const trueKey = s.cc_vigenere_true_key;
  const keyLen = s.cc_vigenere_keylen;
  if (recovered === undefined) {
    return "# Split ciphertext into N streams (one per key position),\n# break each as a Caesar cipher, reassemble the key.\nkey, plaintext = break_vigenere(ciphertext, key_len=5)";
  }
  return [
    `# Recovered key length = ${keyLen} → ${JSON.stringify(recovered)} (true key: ${JSON.stringify(trueKey)})`,
    `key, plaintext = break_vigenere(ciphertext, key_len=${keyLen})`,
  ].join("\n");
};

export const one_time_pad = (_s) => [
  "# OTP: XOR the message with a TRULY RANDOM key of equal length, used ONCE.",
  "key = os.urandom(len(message))",
  "ciphertext = otp_encrypt(message, key)",
].join("\n");

export const perfect_secrecy = (_s) => [
  "# For any ciphertext c and any candidate plaintext p,",
  "# exactly one key k maps p → c:  k = c XOR p  (per byte).",
  "# All keys are equally likely, so P(p | c) = P(p).",
  "# Observing c gives zero information about p. That's perfect secrecy.",
].join("\n");

// Full script — emitted on the Done step.
export function full_script(state) {
  const lines = [HEADER, CAESAR_FUNCS, "", VIGENERE_FUNCS, "", FREQ_FUNCS, "", OTP_FUNCS, ""];

  lines.push("# --- Demo: Caesar ---");
  if (state.cc_caesar_ciphertext && state.cc_caesar_plaintext !== undefined) {
    lines.push(`ciphertext = ${JSON.stringify(state.cc_caesar_ciphertext)}`);
    lines.push(`shift, plaintext = break_caesar(ciphertext)`);
    lines.push(`assert plaintext.lower() == ${JSON.stringify(state.cc_caesar_plaintext.toLowerCase())}`);
    lines.push(`print('Caesar shift:', shift, '→', plaintext)`);
  } else {
    lines.push("print(caesar_encrypt('HELLO', 3))  # → KHOOR");
    lines.push("print(caesar_decrypt('KHOOR', 3))  # → HELLO");
  }
  lines.push("");

  lines.push("# --- Demo: Vigenère + frequency-analysis break ---");
  if (state.cc_vigenere_ciphertext && state.cc_vigenere_recovered_key) {
    lines.push(`ciphertext = ${JSON.stringify(state.cc_vigenere_ciphertext)}`);
    lines.push(`key, plaintext = break_vigenere(ciphertext, key_len=${state.cc_vigenere_keylen})`);
    lines.push(`print('Recovered key:', key)         # ${state.cc_vigenere_recovered_key}`);
    lines.push(`print('Plaintext   :', plaintext)`);
  } else {
    lines.push("ct = vigenere_encrypt('ATTACKATDAWN', 'LEMON')");
    lines.push("print(ct)                              # LXFOPVEFRNHR");
    lines.push("print(vigenere_decrypt(ct, 'LEMON'))   # ATTACKATDAWN");
  }
  lines.push("");

  lines.push("# --- Demo: One-time pad ---");
  lines.push("message = b'meet at dawn'");
  lines.push("key = os.urandom(len(message))         # fresh random pad, never reused");
  lines.push("ct = otp_encrypt(message, key)");
  lines.push("assert otp_decrypt(ct, key) == message");
  lines.push("print('OTP ct (hex):', ct.hex())");

  return lines.join("\n") + "\n";
}
